-- 레시피 더미 100개
INSERT INTO recipes (name, ingredients, instructions, recipe_category_id, created_at, updated_at) VALUES
-- 국/찌개 (5)
('김치찌개', '김치 300g, 돼지고기 200g, 두부 1/2모, 대파 1대, 고춧가루 1T, 다진마늘 1T, 참기름, 소금', '1. 돼지고기를 한입 크기로 썬다\n2. 냄비에 참기름을 두르고 돼지고기를 볶는다\n3. 김치를 넣고 함께 볶는다\n4. 물을 붓고 끓인다\n5. 두부와 대파를 넣고 10분 더 끓인다', (SELECT id FROM recipe_categories WHERE name = '국/찌개'), NOW(), NOW()),
('된장찌개', '된장 2T, 두부 1/2모, 애호박 1/3개, 감자 1개, 대파 1대, 다진마늘 1t, 멸치다시마육수 2컵', '1. 육수를 끓인다\n2. 된장을 풀어 넣는다\n3. 감자, 애호박을 넣고 끓인다\n4. 두부와 대파를 넣고 마무리한다', (SELECT id FROM recipe_categories WHERE name = '국/찌개'), NOW(), NOW()),
('부대찌개', '햄 150g, 소시지 150g, 김치 200g, 두부 1/2모, 라면사리 1개, 고추장 1T, 고춧가루 1T, 다진마늘 1T', '1. 냄비에 재료를 모두 넣는다\n2. 물을 붓고 고추장과 고춧가루를 넣는다\n3. 끓으면 라면사리를 넣고 2분 더 끓인다', (SELECT id FROM recipe_categories WHERE name = '국/찌개'), NOW(), NOW()),
('순두부찌개', '순두부 1봉, 조개 200g, 달걀 1개, 고춧가루 2T, 참기름, 새우젓 1t, 다진마늘 1t', '1. 냄비에 참기름을 두르고 고춧가루를 볶는다\n2. 조개를 넣고 볶다가 물을 붓는다\n3. 순두부를 넣고 끓인다\n4. 달걀을 깨 넣고 새우젓으로 간한다', (SELECT id FROM recipe_categories WHERE name = '국/찌개'), NOW(), NOW()),
('어묵탕', '어묵 300g, 무 200g, 대파 2대, 다시마, 국간장 2T, 소금, 통후추', '1. 다시마와 무로 육수를 낸다\n2. 어묵을 먹기 좋게 썬다\n3. 육수에 어묵을 넣고 국간장으로 간한다\n4. 대파를 넣고 한소끔 더 끓인다', (SELECT id FROM recipe_categories WHERE name = '국/찌개'), NOW(), NOW()),

-- 구이/고기 (5)
('삼겹살구이', '삼겹살 600g, 쌈채소, 쌈장, 마늘, 소금, 참기름', '1. 그릴을 충분히 달군다\n2. 삼겹살을 올리고 소금을 뿌려 굽는다\n3. 양면이 노릇해질 때까지 굽는다\n4. 쌈채소와 쌈장을 곁들인다', (SELECT id FROM recipe_categories WHERE name = '구이/고기'), NOW(), NOW()),
('목살구이', '목살 500g, 마늘 10쪽, 쌈채소, 쌈장, 들기름', '1. 목살을 0.5cm 두께로 썬다\n2. 그릴에 올려 앞뒤로 굽는다\n3. 마늘도 함께 굽는다\n4. 쌈채소와 함께 먹는다', (SELECT id FROM recipe_categories WHERE name = '구이/고기'), NOW(), NOW()),
('돼지갈비구이', '돼지갈비 1kg, 양파 1개, 배 1/4개, 간장 4T, 설탕 2T, 참기름 1T, 다진마늘 1T, 생강', '1. 배와 양파를 갈아 양념을 만든다\n2. 간장, 설탕, 마늘, 참기름을 넣고 섞는다\n3. 갈비에 양념을 입혀 1시간 재운다\n4. 그릴에서 양면을 구워낸다', (SELECT id FROM recipe_categories WHERE name = '구이/고기'), NOW(), NOW()),
('항정살구이', '항정살 400g, 소금, 후추, 참기름, 쌈채소', '1. 항정살을 소금 후추로 간한다\n2. 그릴을 센 불로 달군다\n3. 앞뒤로 노릇하게 굽는다\n4. 참기름을 살짝 바르고 낸다', (SELECT id FROM recipe_categories WHERE name = '구이/고기'), NOW(), NOW()),
('소불고기', '소고기(불고기용) 400g, 양파 1개, 대파 1대, 간장 3T, 설탕 1T, 참기름 1T, 배즙 3T, 다진마늘 1T', '1. 배즙, 간장, 설탕, 마늘로 양념을 만든다\n2. 소고기에 양념을 넣고 30분 재운다\n3. 팬이나 그릴에 양파와 함께 볶는다', (SELECT id FROM recipe_categories WHERE name = '구이/고기'), NOW(), NOW()),

-- 해산물 (4)
('새우구이', '왕새우 10마리, 버터 2T, 레몬 1/2개, 소금, 후추, 허브솔트', '1. 새우 등을 칼집 넣어 손질한다\n2. 그릴을 달구고 새우를 올린다\n3. 버터를 올리고 앞뒤로 굽는다\n4. 허브솔트, 레몬즙을 뿌려 낸다', (SELECT id FROM recipe_categories WHERE name = '해산물'), NOW(), NOW()),
('조개구이', '바지락 300g, 백합 300g, 버터 1T, 다진마늘 1T, 청주 1T', '1. 조개를 해감시킨다\n2. 그릴 위 호일에 조개를 올린다\n3. 버터, 마늘, 청주를 넣는다\n4. 입이 열리면 완성', (SELECT id FROM recipe_categories WHERE name = '해산물'), NOW(), NOW()),
('오징어구이', '오징어 2마리, 고추장 2T, 고춧가루 1T, 간장 1T, 설탕 1T, 참기름, 다진마늘', '1. 오징어를 손질해 칼집을 넣는다\n2. 양념 재료를 모두 섞는다\n3. 오징어에 양념을 바른다\n4. 그릴에 올려 앞뒤로 굽는다', (SELECT id FROM recipe_categories WHERE name = '해산물'), NOW(), NOW()),
('가리비구이', '가리비 10개, 버터 20g, 다진마늘 1T, 파마산치즈, 파슬리', '1. 가리비를 껍데기째 그릴에 올린다\n2. 버터와 마늘을 올린다\n3. 치즈를 뿌리고 녹을 때까지 굽는다\n4. 파슬리를 뿌려 마무리한다', (SELECT id FROM recipe_categories WHERE name = '해산물'), NOW(), NOW()),

-- 간단한 안주 (4)
('소시지구이', '소시지 300g, 케첩, 머스터드', '1. 소시지에 칼집을 낸다\n2. 그릴이나 팬에서 굽는다\n3. 케첩과 머스터드를 곁들인다', (SELECT id FROM recipe_categories WHERE name = '간단한 안주'), NOW(), NOW()),
('치즈 감자', '감자 3개, 체다치즈 슬라이스 3장, 버터 1T, 소금', '1. 감자를 반으로 잘라 호일에 싼다\n2. 불 위에서 30분 굽는다\n3. 포크로 찔러 익으면 열어서 치즈를 올린다\n4. 버터와 소금을 얹는다', (SELECT id FROM recipe_categories WHERE name = '간단한 안주'), NOW(), NOW()),
('마시멜로 초코딥', '마시멜로 1봉, 초코소스, 비스킷', '1. 막대에 마시멜로를 꽂는다\n2. 캠프파이어에서 천천히 돌려가며 굽는다\n3. 초코소스나 비스킷에 찍어 먹는다', (SELECT id FROM recipe_categories WHERE name = '간단한 안주'), NOW(), NOW()),
('명란 버터 구이', '명란젓 2줄, 버터 2T, 청양고추 1개, 레몬', '1. 명란을 반으로 갈라 속을 꺼낸다\n2. 팬에 버터를 녹이고 명란을 굽는다\n3. 청양고추를 잘게 썰어 올린다\n4. 레몬즙을 뿌려 낸다', (SELECT id FROM recipe_categories WHERE name = '간단한 안주'), NOW(), NOW()),

-- 간식 (4)
('고구마구이', '고구마 4개', '1. 고구마를 깨끗이 씻는다\n2. 호일로 감싼다\n3. 숯불 또는 모닥불 가장자리에서 40분 굽는다\n4. 젓가락으로 찔러 부드러우면 완성', (SELECT id FROM recipe_categories WHERE name = '간식'), NOW(), NOW()),
('옥수수구이', '옥수수 4개, 버터 2T, 소금', '1. 옥수수 겉껍질을 벗긴다\n2. 그릴에 올려 돌려가며 굽는다\n3. 버터와 소금을 바르며 굽는다', (SELECT id FROM recipe_categories WHERE name = '간식'), NOW(), NOW()),
('캠핑 떡볶이', '떡볶이 떡 300g, 어묵 200g, 고추장 3T, 고춧가루 1T, 설탕 2T, 간장 1T, 대파', '1. 물에 고추장, 고춧가루, 설탕, 간장을 넣어 끓인다\n2. 떡과 어묵을 넣는다\n3. 대파를 넣고 국물이 자작해질 때까지 끓인다', (SELECT id FROM recipe_categories WHERE name = '간식'), NOW(), NOW()),
('바나나 초코 호일구이', '바나나 2개, 초코칩 30g, 버터 1t', '1. 바나나를 반으로 갈라 속에 칼집을 낸다\n2. 초코칩을 넣고 버터를 올린다\n3. 호일로 감싸 그릴에서 10분 굽는다', (SELECT id FROM recipe_categories WHERE name = '간식'), NOW(), NOW()),

-- 아침식사 (4)
('캠핑 토스트', '식빵 4장, 달걀 2개, 햄 2장, 치즈 2장, 버터, 케첩', '1. 팬에 버터를 녹인다\n2. 달걀을 부친다\n3. 식빵에 달걀, 햄, 치즈를 넣고 눌러가며 굽는다', (SELECT id FROM recipe_categories WHERE name = '아침식사'), NOW(), NOW()),
('베이컨 에그', '베이컨 6장, 달걀 3개, 소금, 후추', '1. 팬에 베이컨을 굽는다\n2. 베이컨 기름에 달걀을 넣고 프라이한다\n3. 소금, 후추로 간한다', (SELECT id FROM recipe_categories WHERE name = '아침식사'), NOW(), NOW()),
('오트밀 죽', '오트밀 1컵, 물 또는 우유 2컵, 꿀 1T, 바나나 1개', '1. 냄비에 오트밀과 물을 넣고 끓인다\n2. 저어가며 5분 익힌다\n3. 꿀을 넣고 바나나를 썰어 올린다', (SELECT id FROM recipe_categories WHERE name = '아침식사'), NOW(), NOW()),
('호떡', '호떡믹스 1봉, 식용유', '1. 호떡믹스에 물을 섞어 반죽한다\n2. 팬에 기름을 두른다\n3. 반죽을 올리고 눌러가며 앞뒤로 굽는다', (SELECT id FROM recipe_categories WHERE name = '아침식사'), NOW(), NOW()),

-- 파스타/면 (4)
('알리오올리오', '스파게티 200g, 마늘 6쪽, 올리브오일 4T, 페페론치노 3개, 파슬리, 소금', '1. 면을 소금물에 삶는다\n2. 팬에 올리브오일로 마늘을 볶는다\n3. 페페론치노를 넣는다\n4. 면수와 면을 넣고 버무린다', (SELECT id FROM recipe_categories WHERE name = '파스타/면'), NOW(), NOW()),
('토마토 파스타', '스파게티 200g, 토마토소스 1캔, 다진마늘 1T, 양파 1/2개, 올리브오일, 소금, 후추, 파마산치즈', '1. 면을 삶는다\n2. 팬에 마늘과 양파를 볶는다\n3. 토마토소스를 넣고 끓인다\n4. 삶은 면을 넣고 버무린다', (SELECT id FROM recipe_categories WHERE name = '파스타/면'), NOW(), NOW()),
('캠핑 우동', '우동면 2인분, 멸치육수 4컵, 간장 2T, 맛술 1T, 소금, 대파, 어묵', '1. 육수를 끓이고 간장, 맛술로 간한다\n2. 어묵을 넣고 끓인다\n3. 우동면을 넣고 익힌다\n4. 대파를 올린다', (SELECT id FROM recipe_categories WHERE name = '파스타/면'), NOW(), NOW()),
('쫄면', '쫄면 2인분, 고추장 2T, 식초 2T, 설탕 1T, 참기름, 오이, 당근, 삶은 달걀', '1. 쫄면을 삶아 찬물에 헹군다\n2. 양념장을 만든다\n3. 채소를 채 썬다\n4. 면에 채소, 달걀을 올리고 양념을 넣어 버무린다', (SELECT id FROM recipe_categories WHERE name = '파스타/면'), NOW(), NOW()),

-- 볶음요리 (5)
('제육볶음', '돼지고기(앞다리) 400g, 양파 1개, 대파 1대, 고추장 2T, 고춧가루 1T, 간장 1T, 설탕 1T, 다진마늘 1T, 참기름, 생강즙', '1. 고추장, 고춧가루, 간장, 설탕, 마늘로 양념을 만든다\n2. 돼지고기에 양념을 넣고 버무린다\n3. 팬에 양파를 볶다가 고기를 넣고 볶는다\n4. 대파를 넣고 참기름으로 마무리한다', (SELECT id FROM recipe_categories WHERE name = '볶음요리'), NOW(), NOW()),
('김치볶음', '묵은 김치 300g, 삼겹살 200g, 참기름, 설탕 1t', '1. 삼겹살을 팬에 먼저 굽는다\n2. 기름이 나오면 김치를 넣는다\n3. 설탕 한 꼬집 넣고 볶는다\n4. 참기름을 뿌려 마무리한다', (SELECT id FROM recipe_categories WHERE name = '볶음요리'), NOW(), NOW()),
('닭갈비볶음', '닭다리살 500g, 고추장 3T, 고춧가루 1T, 설탕 2T, 간장 2T, 참기름, 고구마 1개, 양배추, 대파', '1. 닭에 양념을 입혀 재운다\n2. 팬에 고구마, 양배추를 먼저 볶는다\n3. 닭을 넣고 함께 볶는다\n4. 대파를 넣고 마무리한다', (SELECT id FROM recipe_categories WHERE name = '볶음요리'), NOW(), NOW()),
('오징어볶음', '오징어 2마리, 양파 1개, 대파 1대, 고추장 2T, 고춧가루 1T, 설탕 1T, 간장 1T, 참기름', '1. 오징어를 손질해 먹기 좋게 썬다\n2. 팬에 양파를 먼저 볶는다\n3. 오징어를 넣고 양념과 함께 볶는다\n4. 대파와 참기름으로 마무리한다', (SELECT id FROM recipe_categories WHERE name = '볶음요리'), NOW(), NOW()),
('버섯볶음', '모듬버섯 300g, 마늘 3쪽, 올리브오일 2T, 소금, 후추, 파슬리', '1. 버섯을 먹기 좋게 뜯는다\n2. 팬에 올리브오일과 마늘을 볶는다\n3. 버섯을 넣고 소금, 후추로 간하며 볶는다\n4. 파슬리를 뿌린다', (SELECT id FROM recipe_categories WHERE name = '볶음요리'), NOW(), NOW()),

-- 밥요리 (4)
('캠핑 볶음밥', '밥 2공기, 햄 100g, 달걀 2개, 양파 1/2개, 간장 1T, 참기름, 소금', '1. 팬에 기름을 두르고 햄과 양파를 볶는다\n2. 밥을 넣고 볶는다\n3. 간장으로 간하고 달걀을 넣는다\n4. 참기름으로 마무리한다', (SELECT id FROM recipe_categories WHERE name = '밥요리'), NOW(), NOW()),
('주먹밥', '밥 2공기, 참치 1캔, 김 2장, 참기름, 소금, 깨', '1. 참치를 기름을 빼고 준비한다\n2. 밥에 참기름, 소금, 깨를 넣고 섞는다\n3. 참치를 넣어 주먹밥을 만든다\n4. 김으로 감싼다', (SELECT id FROM recipe_categories WHERE name = '밥요리'), NOW(), NOW()),
('카레라이스', '카레가루 1봉, 감자 2개, 당근 1개, 양파 1개, 닭고기 200g', '1. 채소와 닭고기를 한입 크기로 썬다\n2. 냄비에 기름을 두르고 볶는다\n3. 물을 붓고 끓인다\n4. 카레가루를 풀어 넣고 걸쭉해질 때까지 끓인다', (SELECT id FROM recipe_categories WHERE name = '밥요리'), NOW(), NOW()),
('비빔밥', '밥 2공기, 시금치나물, 콩나물, 당근, 달걀 2개, 고추장, 참기름, 깨', '1. 각 나물을 준비한다\n2. 달걀을 프라이한다\n3. 밥 위에 나물과 달걀을 올린다\n4. 고추장과 참기름을 넣고 비빈다', (SELECT id FROM recipe_categories WHERE name = '밥요리'), NOW(), NOW()),

-- 라면/국수 (4)
('얼큰 라면', '라면 2개, 달걀 2개, 대파, 청양고추 1개, 김치', '1. 물을 끓인다\n2. 스프를 넣고 면을 넣는다\n3. 달걀과 청양고추를 넣는다\n4. 대파와 김치를 올린다', (SELECT id FROM recipe_categories WHERE name = '라면/국수'), NOW(), NOW()),
('짜파게티', '짜파게티 2개, 달걀 2개, 올리브유, 파', '1. 면을 삶는다\n2. 물을 따라내고 분말스프와 후레이크를 넣는다\n3. 달걀 프라이를 올린다\n4. 파를 올려 마무리한다', (SELECT id FROM recipe_categories WHERE name = '라면/국수'), NOW(), NOW()),
('해물라면', '라면 2개, 냉동해물믹스 200g, 달걀 2개, 대파', '1. 물을 끓이고 해물을 넣는다\n2. 스프와 면을 넣는다\n3. 달걀을 풀어 넣는다\n4. 대파를 올린다', (SELECT id FROM recipe_categories WHERE name = '라면/국수'), NOW(), NOW()),
('냉모밀', '메밀면 2인분, 쯔유 4T, 냉수 1컵, 얼음, 무, 파, 김', '1. 면을 삶아 찬물에 헹군다\n2. 쯔유와 냉수로 소바 국물을 만든다\n3. 얼음을 담은 그릇에 면을 올린다\n4. 무즙, 파, 김을 곁들인다', (SELECT id FROM recipe_categories WHERE name = '라면/국수'), NOW(), NOW()),

-- 전/부침개 (3)
('김치전', '김치 200g, 부침가루 1컵, 물 1컵, 식용유', '1. 김치를 잘게 썬다\n2. 부침가루와 물을 섞어 반죽한다\n3. 김치를 반죽에 넣고 섞는다\n4. 팬에 기름을 두르고 노릇하게 굽는다', (SELECT id FROM recipe_categories WHERE name = '전/부침개'), NOW(), NOW()),
('해물파전', '해물믹스 200g, 쪽파 150g, 부침가루 1컵, 달걀 1개, 물, 식용유', '1. 반죽을 만든다\n2. 달궈진 팬에 기름을 두른다\n3. 파를 깔고 해물을 올린 뒤 반죽을 붓는다\n4. 앞뒤로 노릇하게 굽는다', (SELECT id FROM recipe_categories WHERE name = '전/부침개'), NOW(), NOW()),
('감자전', '감자 3개, 소금, 식용유', '1. 감자를 강판에 간다\n2. 물기를 짜낸다\n3. 소금으로 간한다\n4. 팬에 기름을 두르고 노릇하게 굽는다', (SELECT id FROM recipe_categories WHERE name = '전/부침개'), NOW(), NOW()),

-- 찜요리 (3)
('닭찜', '닭 1마리, 감자 2개, 당근 1개, 간장 3T, 설탕 1T, 참기름, 다진마늘 1T, 청양고추', '1. 닭을 토막 낸다\n2. 냄비에 닭을 넣고 양념과 물을 붓는다\n3. 감자, 당근을 넣고 끓인다\n4. 국물이 자작해질 때까지 조린다', (SELECT id FROM recipe_categories WHERE name = '찜요리'), NOW(), NOW()),
('갈비찜', '돼지갈비 1kg, 무 200g, 당근 1개, 간장 4T, 설탕 2T, 배즙 3T, 다진마늘 1T', '1. 갈비를 찬물에 담가 핏물을 뺀다\n2. 양념을 만든다\n3. 냄비에 갈비와 야채, 양념을 넣고 끓인다\n4. 약불에서 1시간 조린다', (SELECT id FROM recipe_categories WHERE name = '찜요리'), NOW(), NOW()),
('감자찜', '감자 4개, 버터 1T, 소금, 사워크림(선택)', '1. 감자를 씻어 반으로 자른다\n2. 냄비 찜기에 물을 붓고 감자를 올린다\n3. 20분 쪄낸다\n4. 버터와 소금을 올려 먹는다', (SELECT id FROM recipe_categories WHERE name = '찜요리'), NOW(), NOW()),

-- BBQ (4)
('바비큐 폭립', '폭립 1kg, 바비큐소스 200ml, 소금, 후추, 파프리카가루', '1. 폭립에 소금, 후추, 파프리카가루를 바른다\n2. 그릴에서 40분 굽는다\n3. 바비큐소스를 바르며 10분 더 굽는다', (SELECT id FROM recipe_categories WHERE name = 'BBQ'), NOW(), NOW()),
('바비큐 치킨', '닭다리 6개, 바비큐소스, 소금, 후추, 마늘가루', '1. 닭에 소금, 후추, 마늘가루로 밑간한다\n2. 그릴에서 앞뒤로 굽는다\n3. 바비큐소스를 발라가며 마무리한다', (SELECT id FROM recipe_categories WHERE name = 'BBQ'), NOW(), NOW()),
('바비큐 옥수수', '옥수수 4개, 버터 2T, 바비큐소스', '1. 옥수수 겉껍질을 일부 남긴다\n2. 그릴에서 돌려가며 굽는다\n3. 버터와 바비큐소스를 발라가며 구워낸다', (SELECT id FROM recipe_categories WHERE name = 'BBQ'), NOW(), NOW()),
('바비큐 소시지', '훈제소시지 300g, 바비큐소스, 머스터드', '1. 소시지에 칼집을 낸다\n2. 그릴에서 앞뒤로 굽는다\n3. 바비큐소스와 머스터드를 곁들인다', (SELECT id FROM recipe_categories WHERE name = 'BBQ'), NOW(), NOW()),

-- 스테이크 (3)
('등심 스테이크', '등심 400g, 버터 2T, 마늘 3쪽, 로즈마리, 소금, 후추', '1. 고기를 실온에 30분 꺼내둔다\n2. 소금, 후추를 고루 뿌린다\n3. 달군 팬에 버터를 두르고 굽는다\n4. 마늘, 로즈마리와 함께 버터로 계속 끼얹으며 굽는다', (SELECT id FROM recipe_categories WHERE name = '스테이크'), NOW(), NOW()),
('채끝 스테이크', '채끝 400g, 소금, 후추, 버터, 타임', '1. 고기 앞뒤에 소금, 후추를 뿌린다\n2. 강불 팬에서 앞뒤 2분씩 굽는다\n3. 버터와 타임을 넣고 1분 더 끼얹으며 굽는다\n4. 5분 레스팅 후 썬다', (SELECT id FROM recipe_categories WHERE name = '스테이크'), NOW(), NOW()),
('철판 스테이크', '소고기(스테이크용) 300g, 양송이 100g, 양파 1/2개, 버터, 소금, 후추', '1. 철판을 강불로 달군다\n2. 소고기를 올리고 굽는다\n3. 양송이, 양파를 함께 볶는다\n4. 버터를 넣어 마무리한다', (SELECT id FROM recipe_categories WHERE name = '스테이크'), NOW(), NOW()),

-- 닭요리 (3)
('닭꼬치', '닭다리살 300g, 간장 2T, 미림 2T, 설탕 1T, 참기름, 대파', '1. 닭을 한입 크기로 썰어 꼬치에 꿴다\n2. 양념을 만든다\n3. 그릴에서 구우며 양념을 발라 마무리한다', (SELECT id FROM recipe_categories WHERE name = '닭요리'), NOW(), NOW()),
('닭볶음탕', '닭 반 마리, 감자 2개, 당근 1개, 고추장 2T, 고춧가루 1T, 간장 2T, 설탕 1T', '1. 닭을 토막 내고 끓는 물에 데친다\n2. 냄비에 닭과 야채를 넣고 양념과 물을 붓는다\n3. 40분 끓인다', (SELECT id FROM recipe_categories WHERE name = '닭요리'), NOW(), NOW()),
('캠핑 통닭구이', '닭 1마리, 허브솔트, 올리브오일, 레몬, 마늘', '1. 닭 안팎에 허브솔트와 올리브오일을 바른다\n2. 레몬과 마늘을 속에 넣는다\n3. 그릴에서 회전시키며 1시간 굽는다', (SELECT id FROM recipe_categories WHERE name = '닭요리'), NOW(), NOW()),

-- 두부요리 (3)
('두부조림', '두부 1모, 간장 2T, 고춧가루 1T, 설탕 1t, 참기름, 파, 다진마늘', '1. 두부를 도톰하게 썬다\n2. 팬에 기름을 두르고 두부를 앞뒤로 굽는다\n3. 양념을 넣고 조린다\n4. 파와 참기름을 뿌린다', (SELECT id FROM recipe_categories WHERE name = '두부요리'), NOW(), NOW()),
('두부김치', '두부 1모, 묵은 김치 200g, 삼겹살 100g, 참기름', '1. 두부를 삶아 도톰하게 썬다\n2. 삼겹살을 볶다가 김치를 넣는다\n3. 참기름으로 마무리한다\n4. 두부 위에 볶은 김치를 올린다', (SELECT id FROM recipe_categories WHERE name = '두부요리'), NOW(), NOW()),
('순두부 스크램블', '순두부 1봉, 달걀 2개, 대파, 참기름, 소금', '1. 팬에 참기름을 두른다\n2. 순두부를 넣고 으깬다\n3. 달걀을 풀어 넣고 볶는다\n4. 대파와 소금으로 간한다', (SELECT id FROM recipe_categories WHERE name = '두부요리'), NOW(), NOW()),

-- 계란요리 (3)
('계란말이', '달걀 4개, 당근 30g, 시금치 30g, 소금, 식용유', '1. 당근과 시금치를 잘게 썬다\n2. 달걀을 풀고 채소, 소금을 넣는다\n3. 팬에 기름을 두르고 달걀물을 부어 말아낸다', (SELECT id FROM recipe_categories WHERE name = '계란요리'), NOW(), NOW()),
('계란찜', '달걀 3개, 물 1컵, 새우젓 1t, 대파, 참기름', '1. 달걀과 물을 1:1.5 비율로 섞는다\n2. 새우젓으로 간한다\n3. 냄비에 붓고 뚜껑 닫아 10분 찐다\n4. 대파와 참기름을 올린다', (SELECT id FROM recipe_categories WHERE name = '계란요리'), NOW(), NOW()),
('스크램블 에그', '달걀 4개, 버터 1T, 우유 2T, 소금, 후추', '1. 달걀에 우유, 소금, 후추를 넣고 푼다\n2. 팬에 버터를 녹인다\n3. 달걀물을 붓고 천천히 저어가며 익힌다', (SELECT id FROM recipe_categories WHERE name = '계란요리'), NOW(), NOW()),

-- 나물/채소 (2)
('콩나물무침', '콩나물 300g, 다진마늘 1t, 참기름 1T, 소금, 깨', '1. 콩나물을 끓는 물에 데친다\n2. 찬물에 헹구고 물기를 뺀다\n3. 마늘, 참기름, 소금을 넣고 무친다\n4. 깨를 뿌린다', (SELECT id FROM recipe_categories WHERE name = '나물/채소'), NOW(), NOW()),
('브로콜리 버터볶음', '브로콜리 1개, 버터 1T, 마늘 2쪽, 소금, 후추', '1. 브로콜리를 먹기 좋게 자른다\n2. 팬에 버터와 마늘을 볶는다\n3. 브로콜리를 넣고 소금, 후추로 볶는다', (SELECT id FROM recipe_categories WHERE name = '나물/채소'), NOW(), NOW()),

-- 조림 (2)
('감자조림', '감자 4개, 간장 3T, 설탕 1T, 참기름, 깨', '1. 감자를 먹기 좋게 썬다\n2. 냄비에 감자, 간장, 설탕, 물을 넣고 끓인다\n3. 국물이 자작해질 때까지 조린다\n4. 참기름과 깨로 마무리한다', (SELECT id FROM recipe_categories WHERE name = '조림'), NOW(), NOW()),
('연근조림', '연근 200g, 간장 3T, 설탕 1T, 올리고당 1T, 참기름', '1. 연근을 둥글게 썰어 식초물에 담근다\n2. 팬에 연근과 양념을 넣고 볶는다\n3. 물을 자박하게 넣고 조린다\n4. 참기름으로 마무리한다', (SELECT id FROM recipe_categories WHERE name = '조림'), NOW(), NOW()),

-- 원팟요리 (3)
('캠핑 전골', '두부 1/2모, 버섯 200g, 소고기 200g, 배추 200g, 다시마육수 3컵, 간장, 소금', '1. 냄비에 육수를 붓는다\n2. 재료를 모두 넣는다\n3. 끓으면 간장, 소금으로 간한다', (SELECT id FROM recipe_categories WHERE name = '원팟요리'), NOW(), NOW()),
('부대전골', '햄 150g, 소시지 150g, 베이컨 100g, 버섯 100g, 두부 1/4모, 라면사리, 고추장 1T, 육수', '1. 냄비에 재료를 모두 담는다\n2. 육수를 붓고 고추장을 넣는다\n3. 끓으면 라면사리를 추가한다', (SELECT id FROM recipe_categories WHERE name = '원팟요리'), NOW(), NOW()),
('해물전골', '해물믹스 300g, 배추 200g, 버섯 150g, 두부 1/2모, 육수 3컵, 소금, 청양고추', '1. 육수를 끓인다\n2. 배추, 버섯, 두부를 넣는다\n3. 해물을 넣고 소금으로 간한다\n4. 청양고추로 매운맛을 조절한다', (SELECT id FROM recipe_categories WHERE name = '원팟요리'), NOW(), NOW()),

-- 훈제요리 (2)
('훈제 연어', '연어 400g, 소금 2T, 설탕 1T, 레몬, 딜', '1. 연어에 소금과 설탕을 문질러 1시간 재운다\n2. 훈제칩을 준비한다\n3. 그릴 뚜껑을 닫고 훈연 상태에서 30분 굽는다\n4. 레몬과 딜을 곁들인다', (SELECT id FROM recipe_categories WHERE name = '훈제요리'), NOW(), NOW()),
('훈제 닭가슴살', '닭가슴살 4개, 소금, 후추, 파프리카가루, 훈제칩', '1. 닭에 소금, 후추, 파프리카가루를 바른다\n2. 훈제칩을 그릴 하단에 넣는다\n3. 뚜껑을 닫고 40분 훈연 굽기한다', (SELECT id FROM recipe_categories WHERE name = '훈제요리'), NOW(), NOW()),

-- 디저트 (2)
('스모어', '마시멜로 1봉, 초코바 2개, 그래햄 크래커', '1. 마시멜로를 꼬치에 꽂는다\n2. 불 위에서 노릇하게 굽는다\n3. 크래커 위에 초코바를 올리고 구운 마시멜로를 넣어 샌드위치처럼 먹는다', (SELECT id FROM recipe_categories WHERE name = '디저트'), NOW(), NOW()),
('캠핑 식빵 피자', '식빵 4장, 피자소스, 모짜렐라치즈, 페퍼로니, 파프리카', '1. 식빵에 피자소스를 바른다\n2. 치즈, 페퍼로니, 파프리카를 올린다\n3. 팬 뚜껑을 닫고 치즈가 녹을 때까지 굽는다', (SELECT id FROM recipe_categories WHERE name = '디저트'), NOW(), NOW()),

-- 음료/차 (2)
('캠핑 뱅쇼', '레드와인 1병, 오렌지 1개, 레몬 1개, 계피 2개, 정향 5개, 꿀 2T', '1. 냄비에 와인을 붓는다\n2. 과일을 썰어 넣는다\n3. 계피, 정향, 꿀을 넣는다\n4. 약불에서 20분 끓인다', (SELECT id FROM recipe_categories WHERE name = '음료/차'), NOW(), NOW()),
('모닥불 코코아', '코코아가루 2T, 우유 300ml, 설탕 1T, 마시멜로', '1. 냄비에 우유를 따뜻하게 데운다\n2. 코코아가루와 설탕을 넣고 녹인다\n3. 컵에 담고 마시멜로를 올린다', (SELECT id FROM recipe_categories WHERE name = '음료/차'), NOW(), NOW()),

-- 빵/토스트 (2)
('프렌치토스트', '식빵 4장, 달걀 3개, 우유 1/2컵, 버터 1T, 설탕 1T, 시나몬가루', '1. 달걀, 우유, 설탕, 시나몬을 섞는다\n2. 식빵을 달걀물에 적신다\n3. 팬에 버터를 두르고 앞뒤로 노릇하게 굽는다', (SELECT id FROM recipe_categories WHERE name = '빵/토스트'), NOW(), NOW()),
('어니언 토스트', '식빵 4장, 버터 2T, 양파 1개, 설탕 1T, 소금', '1. 양파를 얇게 썰어 버터에 카라멜화될 때까지 볶는다\n2. 식빵에 버터를 바른다\n3. 카라멜 양파를 올리고 굽는다', (SELECT id FROM recipe_categories WHERE name = '빵/토스트'), NOW(), NOW()),

-- 샐러드 (2)
('캠핑 콥샐러드', '닭가슴살 200g, 달걀 2개, 베이컨 4장, 아보카도 1개, 방울토마토 10개, 양상추, 드레싱', '1. 닭가슴살을 삶아 썬다\n2. 달걀을 삶는다\n3. 베이컨을 굽는다\n4. 모든 재료를 그릇에 담고 드레싱을 뿌린다', (SELECT id FROM recipe_categories WHERE name = '샐러드'), NOW(), NOW()),
('감자 샐러드', '감자 3개, 마요네즈 3T, 오이 1/2개, 삶은 달걀 2개, 소금, 후추', '1. 감자를 삶아 으깬다\n2. 오이를 작게 썬다\n3. 달걀을 으깬다\n4. 마요네즈, 소금, 후추로 버무린다', (SELECT id FROM recipe_categories WHERE name = '샐러드'), NOW(), NOW()),

-- 도시락 (2)
('캠핑 도시락', '밥 2공기, 계란말이 2줄, 소시지 4개, 브로콜리, 당근', '1. 소시지와 채소를 볶는다\n2. 계란말이를 만든다\n3. 도시락 통에 밥을 담고 반찬을 예쁘게 담는다', (SELECT id FROM recipe_categories WHERE name = '도시락'), NOW(), NOW()),
('김밥', '밥 2공기, 김 4장, 시금치, 당근, 단무지, 햄, 달걀, 참기름, 소금', '1. 밥에 참기름과 소금을 넣고 버무린다\n2. 재료를 준비한다\n3. 김 위에 밥을 펴고 재료를 올려 만다\n4. 먹기 좋게 썬다', (SELECT id FROM recipe_categories WHERE name = '도시락'), NOW(), NOW()),

-- 수프 (2)
('크림 감자수프', '감자 4개, 버터 2T, 양파 1개, 우유 2컵, 치킨스톡, 소금, 후추', '1. 양파를 버터에 볶는다\n2. 감자와 육수를 넣고 끓인다\n3. 감자가 익으면 핸드블렌더로 간다\n4. 우유를 넣고 소금, 후추로 간한다', (SELECT id FROM recipe_categories WHERE name = '수프'), NOW(), NOW()),
('토마토수프', '토마토 4개, 양파 1/2개, 버터 1T, 치킨스톡, 바질, 소금, 후추', '1. 토마토와 양파를 볶는다\n2. 육수를 넣고 끓인다\n3. 믹서에 갈거나 으깬다\n4. 바질로 마무리한다', (SELECT id FROM recipe_categories WHERE name = '수프'), NOW(), NOW()),

-- 소시지/햄 (2)
('부타동 스타일 소시지 덮밥', '소시지 4개, 양파 1/2개, 간장 2T, 미림 1T, 설탕 1t, 밥 2공기', '1. 소시지와 양파를 볶는다\n2. 간장, 미림, 설탕으로 양념한다\n3. 밥 위에 올린다', (SELECT id FROM recipe_categories WHERE name = '소시지/햄'), NOW(), NOW()),
('햄 치즈 철판볶음', '햄 200g, 체다치즈 2장, 양파 1/2개, 버터 1T, 후추', '1. 철판에 버터를 두른다\n2. 양파를 볶다가 햄을 넣는다\n3. 치즈를 올리고 후추를 뿌린다', (SELECT id FROM recipe_categories WHERE name = '소시지/햄'), NOW(), NOW()),

-- 무침 (2)
('오이무침', '오이 2개, 소금 1T, 고추장 1T, 식초 1T, 설탕 1t, 참기름, 깨, 다진마늘', '1. 오이를 어슷하게 썬다\n2. 소금에 절인 뒤 물기를 뺀다\n3. 양념을 만들어 무친다\n4. 깨를 뿌린다', (SELECT id FROM recipe_categories WHERE name = '무침'), NOW(), NOW()),
('미역무침', '미역 100g, 간장 2T, 식초 2T, 설탕 1T, 참기름, 깨, 다진마늘', '1. 미역을 물에 불려 적당히 자른다\n2. 끓는 물에 데쳐 찬물에 헹군다\n3. 양념을 넣고 무친다', (SELECT id FROM recipe_categories WHERE name = '무침'), NOW(), NOW()),

-- 즉석응용식 (2)
('컵라면 업그레이드', '컵라면 2개, 달걀 2개, 소시지 2개, 청양고추 1개, 대파', '1. 컵라면에 뜨거운 물을 붓는다\n2. 별도 팬에 소시지와 달걀을 굽는다\n3. 익은 라면에 소시지, 달걀을 올린다\n4. 청양고추와 대파를 더한다', (SELECT id FROM recipe_categories WHERE name = '즉석응용식'), NOW(), NOW()),
('즉석 나베', '즉석 나베 수프 1팩, 모듬채소 200g, 두부 1/4모, 버섯 100g, 당면', '1. 냄비에 나베 수프와 물을 넣는다\n2. 채소, 두부, 버섯을 넣는다\n3. 끓이면서 당면을 마지막에 넣는다', (SELECT id FROM recipe_categories WHERE name = '즉석응용식'), NOW(), NOW()),

-- 추가 8개 (각 카테고리 보충)
('양념 돼지갈비', '돼지갈비 1kg, 간장 4T, 설탕 2T, 배즙 3T, 사과즙 2T, 다진마늘 1T, 참기름, 후추', '1. 갈비를 찬물에 30분 담가 핏물을 뺀다\n2. 양념 재료를 섞는다\n3. 갈비에 양념을 버무려 2시간 이상 재운다\n4. 그릴에서 앞뒤로 노릇하게 굽는다', (SELECT id FROM recipe_categories WHERE name = '구이/고기'), NOW(), NOW()),
('두부 야채볶음', '두부 1모, 양파 1개, 파프리카 1개, 애호박 1/2개, 간장 2T, 굴소스 1T, 참기름', '1. 두부를 깍뚝썰기해 팬에 노릇하게 굽는다\n2. 야채를 볶는다\n3. 간장과 굴소스로 간한다\n4. 참기름으로 마무리한다', (SELECT id FROM recipe_categories WHERE name = '볶음요리'), NOW(), NOW()),
('바비큐 새우꼬치', '왕새우 16마리, 바비큐소스 3T, 올리브오일 1T, 마늘가루, 파프리카가루, 소금', '1. 새우를 손질해 꼬치에 꿴다\n2. 올리브오일, 마늘가루, 소금으로 밑간한다\n3. 그릴에서 앞뒤로 굽는다\n4. 바비큐소스를 바르며 마무리한다', (SELECT id FROM recipe_categories WHERE name = 'BBQ'), NOW(), NOW()),
('호박전', '애호박 1개, 부침가루 1/2컵, 달걀 1개, 소금, 식용유', '1. 애호박을 0.5cm 두께로 썬다\n2. 소금을 뿌려 10분 절인 후 물기를 뺀다\n3. 부침가루를 입히고 달걀물을 씌운다\n4. 팬에 기름을 두르고 앞뒤로 노릇하게 굽는다', (SELECT id FROM recipe_categories WHERE name = '전/부침개'), NOW(), NOW()),
('볼로네제 파스타', '스파게티 200g, 다진소고기 200g, 토마토소스 1캔, 양파 1/2개, 마늘 3쪽, 올리브오일, 소금, 후추, 파마산치즈', '1. 면을 삶는다\n2. 팬에 마늘과 양파를 볶는다\n3. 다진 소고기를 넣고 볶는다\n4. 토마토소스를 넣고 끓인다\n5. 면과 버무려 치즈를 뿌린다', (SELECT id FROM recipe_categories WHERE name = '파스타/면'), NOW(), NOW()),
('야채전골', '배추 200g, 버섯 150g, 애호박 1/2개, 당근 1/2개, 두부 1/2모, 다시마육수 3컵, 국간장 2T', '1. 육수를 끓인다\n2. 야채를 먹기 좋게 썬다\n3. 냄비에 야채와 두부를 넣고 끓인다\n4. 국간장으로 간한다', (SELECT id FROM recipe_categories WHERE name = '원팟요리'), NOW(), NOW()),
('캠핑 달걀 샌드위치', '식빵 4장, 달걀 3개, 마요네즈 2T, 소금, 후추, 양상추', '1. 달걀을 삶아 으깬다\n2. 마요네즈, 소금, 후추를 넣고 섞는다\n3. 식빵에 양상추를 깔고 달걀 샐러드를 올린다\n4. 식빵으로 덮는다', (SELECT id FROM recipe_categories WHERE name = '아침식사'), NOW(), NOW()),
('아이스 캠핑 커피', '에스프레소 2샷(또는 인스턴트 커피 2T), 얼음 1컵, 우유 1컵, 설탕(선택)', '1. 진한 커피를 만든다\n2. 컵에 얼음을 가득 담는다\n3. 우유를 붓는다\n4. 커피를 천천히 붓는다', (SELECT id FROM recipe_categories WHERE name = '음료/차'), NOW(), NOW());
